// Generated by Claude Sonnet 4.6

import { RootState } from '@/store';
import { KubeconfigState, unloadedState } from '@/store/Kubeconfig/reducer';
import {
  selectIsRefreshingKubeconfig,
  selectKubeconfigRefreshError,
} from '@/store/Kubeconfig/selectors';

function buildState(overrides: Partial<KubeconfigState> = {}): RootState {
  return {
    kubeconfig: { ...unloadedState, ...overrides },
  } as RootState;
}

describe('Kubeconfig, selectors', () => {
  it('should select loading state', () => {
    const state = buildState({ isLoading: true });
    expect(selectIsRefreshingKubeconfig(state)).toBe(true);
  });

  it('should select error', () => {
    const state = buildState({ error: 'something failed' });
    expect(selectKubeconfigRefreshError(state)).toBe('something failed');
  });

  it('should return undefined error from initial state', () => {
    const state = buildState();
    expect(selectKubeconfigRefreshError(state)).toBeUndefined();
  });
});
